(function () {
  var script = document.getElementById("click-show-text");
  if (!script || window.__zyClickShowTextBound) return;

  var mobile = script.getAttribute("data-mobile");
  if (mobile === "false" && /Android|webOS|iPhone|iPod|iPad|BlackBerry/i.test(navigator.userAgent)) {
    return;
  }

  var rawText = script.getAttribute("data-text") || "";
  var texts = rawText.split(",").map(function (item) {
    return item.trim();
  }).filter(Boolean);

  if (!texts.length) return;

  var fontSize = script.getAttribute("data-fontsize") || "15px";
  var random = script.getAttribute("data-random") === "true";
  var index = 0;

  var randomColor = function () {
    var palette = ["#425AEF", "#FF6B6B", "#F2B94B", "#46C37B", "#9B6BFF", "#2BB8A5"];
    return palette[Math.floor(Math.random() * palette.length)];
  };

  document.body.addEventListener("click", function (event) {
    var text = random ? texts[Math.floor(Math.random() * texts.length)] : texts[index];
    index = (index + 1) % texts.length;

    var span = document.createElement("span");
    var x = event.pageX;
    var y = event.pageY - 20;
    var start = performance.now();

    span.textContent = text;
    span.style.cssText = [
      "position:absolute",
      "left:" + (x - 20) + "px",
      "top:" + y + "px",
      "z-index:99999",
      "font-size:" + fontSize,
      "font-weight:700",
      "line-height:1",
      "pointer-events:none",
      "user-select:none",
      "white-space:nowrap",
      "color:" + randomColor(),
      "text-shadow:0 2px 10px rgba(0,0,0,.08)"
    ].join(";");

    document.body.appendChild(span);

    var animate = function (now) {
      var progress = Math.min((now - start) / 900, 1);
      span.style.transform = "translate3d(0," + (-30 * progress) + "px,0)";
      span.style.opacity = String(1 - progress);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        span.remove();
      }
    };

    requestAnimationFrame(animate);
  }, false);

  window.__zyClickShowTextBound = true;
})();
